import re, anthropic

# Simple pre-flight scan for prohibited content patterns in prompts
# This is illustrative — production implementations use more sophisticated NLP

PROHIBITED_PATTERNS = [
    (r'\bSSN\b|\bsocial security\b', "SSN in prompt — not approved for this model entry"),
    (r'\bpassword\b.*\b(hash|salt|bcrypt)\b', "Credential data in prompt"),
    (r'\b(credit card|card number|CVV|CVC)\b', "Payment card data — PCI scope; not approved"),
]

def scan_prompt(prompt: str) -> list[str]:
    """Return list of violation messages; empty list means prompt is clean."""
    violations = []
    for pattern, message in PROHIBITED_PATTERNS:
        if re.search(pattern, prompt, re.IGNORECASE):
            violations.append(message)
    return violations

client = anthropic.Anthropic()

def safe_create(messages: list, **kwargs):
    for msg in messages:
        if msg.get("role") == "user":
            violations = scan_prompt(str(msg.get("content", "")))
            if violations:
                raise ValueError(f"Prompt blocked by content policy: {'; '.join(violations)}")
    return client.messages.create(messages=messages, **kwargs)
